_____javascript
const path = "~/contacts.yaml"
const text = await space.api.fileRead(path, "utf8")
const data = space.utils.yaml.parse(text)

function updateValue(obj) {
  if (Array.isArray(obj)) {
    return obj.map(updateValue)
  }
  if (obj && typeof obj === "object") {
    for (const key of Object.keys(obj)) {
      if (key === "mr_kowalski" && typeof obj[key] === "string") {
        obj[key] = "John Ronald Kowalski"
      } else {
        obj[key] = updateValue(obj[key])
      }
    }
  }
  return obj
}

const updated = updateValue(data)
return await space.api.fileWrite(path, space.utils.yaml.stringify(updated), "utf8")

